    // Calculate the actual number of bytes to peek (cannot exceed buffer size)
    size_t actual_bytes = std::min(bytes_to_peek, buffer.size());

    // Create a destination vector to hold the peeked data
    std::vector<uint8_t> result(actual_bytes);

    // Use the copy() method to copy data without advancing the read pointer
    adaptor.copy(result.data(), actual_bytes);

    // Return the copied data
    return result;
