    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Write the header
    stream.write(&header, sizeof(header));

    // Write the items container using write_container
    stream.write_container(items);

    // Return success status based on write operation
    // Check if stream is still in good state
    return stream.good();
}
