    std::cout << "Allocated third block (popped from free list, value: " << *ptr3 << ")\n";

    // Deallocate second block - triggers push() to free list
    alloc.deallocate(ptr2);
    std::cout << "Deallocated second block (pushed to free list)\n";

    // Fourth allocation - triggers pop() from free list (now contains one block)
    int* ptr4 = alloc.allocate(48);
    std::cout << "Allocated fourth block (popped from free list, value: " << *ptr4 << ")\n";

    // Deallocate third block - triggers push() to free list
    alloc.deallocate(ptr3);
    std::cout << "Deallocated third block (pushed to free list)\n";

    // Deallocate fourth block - triggers push() to free list
    alloc.deallocate(ptr4);
    std::cout << "Deallocated fourth block (pushed to free list)\n";

    // Demonstrate fallback to new when preallocated slab is exhausted
    // Allocate beyond preallocated capacity (element_count)
    int* ptr5 = alloc.allocate(60);
    std::cout << "Allocated fifth block (using fallback to new, value: " << *ptr5 << ")\n";

    // Deallocate the fallback allocation
    alloc.deallocate(ptr5);
    std::cout << "Deallocated fifth block (returned via delete[])\n";

    std::cout << "Free list management demonstration complete.\n";
}

// Additional helper function to show the internal structure
template<size_t element_count = 10>
void show_free_list_operations() {
    hexi::block_allocator<int, element_count> alloc;

    std::cout << "\nDetailed free list operation sequence:\n";

    // Initial state: free list is empty
    std::cout << "Initial state: free list is empty\n";

    // Operation 1: allocate() - triggers pop() on empty list
    int* a1 = alloc.allocate(100);
    std::cout << "Operation 1: allocate() - pop() called on empty list -> uses preallocated slab\n";

    // Operation 2: deallocate() - triggers push() to add to free list
    alloc.deallocate(a1);
    std::cout << "Operation 2: deallocate() - push() adds block to free list head\n";

    // Operation 3: allocate() - triggers pop() from non-empty list
    int* a2 = alloc.allocate(200);
    std::cout << "Operation 3: allocate() - pop() retrieves block from free list head\n";

    // Operation 4: deallocate() - triggers push() to maintain free list
    alloc.deallocate(a2);
    std::cout << "Operation 4: deallocate() - push() maintains LIFO order\n";

    std::cout << "Free list operations demonstrated successfully.\n";
}

