Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian
        adaptor.write(&sensor_id, sizeof(sensor_id));

        for (const auto& temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse(temp, 
                                                             std::endian::native, 
                                                             std::endian::little);
            adaptor.write(&converted, sizeof(converted));
        }

        auto converted_pressure = hexi::endian::conditional_reverse(pressure,
                                                                  std::endian::native,
                                                                  std::endian::little);
        adaptor.write(&converted_pressure, sizeof(converted_pressure));
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.read(&sensor_id, sizeof(sensor_id));

        for (auto& temp : temperatures) {
            float read_temp;
            adaptor.read(&read_temp, sizeof(read_temp));
            hexi::endian::little_to_native_inplace(read_temp);
            temp = read_temp;
        }

        double read_pressure;
        adaptor.read(&read_pressure, sizeof(read_pressure));
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    hexi::Buffer buffer;
    hexi::binary_stream stream(buffer);
    stream.serialise(data);
    return buffer.to_vector();
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::Buffer buf;
    buf.write(buffer.data(), buffer.size());
    hexi::binary_stream stream(buf);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::Buffer buf;
    buf.write(buffer.data(), buffer.size());
    hexi::binary_stream stream(buf);

    // Extract sensor name using view (null-terminated string)
    std::string_view sensor_name = stream.view();

    // Check if there's enough data for sensor_id using enforce_read_bounds
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id
    uint32_t sensor_id;
    stream.read(&sensor_id, sizeof(sensor_id));

    // Skip remaining data
    size_t remaining_bytes = buffer.size() - (sensor_name.size() + sizeof(sensor_id));
    if (remaining_bytes > 0) {
        stream.skip(remaining_bytes);
    }

    return {sensor_id, sensor_name};
}
```

